// Image Lightbox Logic
document.addEventListener('DOMContentLoaded', function() {
    // Create Lightbox Elements dynamically
    const lightbox = document.createElement('div');
    lightbox.id = 'image-lightbox';
    lightbox.className = 'lightbox';
    lightbox.innerHTML = '<span class="close-lightbox">&times;</span><img class="lightbox-content" id="lightbox-img">';
    document.body.appendChild(lightbox);

    const lightboxImg = document.getElementById('lightbox-img');
    const closeBtn = lightbox.querySelector('.close-lightbox');

    // Select all project thumbnails (images with class 'post-thumb')
    const images = document.querySelectorAll('.post-thumb');

    images.forEach(img => {
        // Ensure the parent anchor doesn't trigger navigation when image is clicked
        img.addEventListener('click', function(e) {
            e.preventDefault(); // Prevent default link behavior
            e.stopPropagation(); // Stop event bubbling

            lightbox.style.display = 'block';
            lightboxImg.src = this.src;
            lightboxImg.alt = this.alt;
        });

        // Optional: Add a visual cue that the image is clickable
        img.style.cursor = 'zoom-in';
    });

    // Close Logic
    const closeLightbox = () => {
        lightbox.style.display = 'none';
    };

    if (closeBtn) {
        closeBtn.addEventListener('click', closeLightbox);
    }

    lightbox.addEventListener('click', function(e) {
        if (e.target === lightbox) {
            closeLightbox();
        }
    });

    // Close on Escape key
    document.addEventListener('keydown', function(e) {
        if (e.key === 'Escape' && lightbox.style.display === 'block') {
            closeLightbox();
        }
    });
});

/* CTA Sidebar */
.cta-sidebar {
  float: right;
  width: 300px;
  margin: 0 0 1.5rem 2rem;
  background: linear-gradient(135deg, #fafffe 0%, #f8fffe 100%);
  padding: 1.5rem;
  border-radius: 16px;
  border: 2px solid #177c72;
  box-shadow: 0 4px 12px rgba(23, 124, 114, 0.1);
  text-align: center;
  clear: right;
}

.cta-sidebar h3 {
  color: #177c72;
  margin: 0 0 0.5rem 0;
  font-size: 1.3rem;
  font-weight: 600;
  letter-spacing: -0.02em;
}

.cta-sidebar p {
  margin: 0 0 1rem 0;
  color: #475569;
  font-size: 0.95rem;
  line-height: 1.4;
}

.cta-sidebar .button-container {
  flex-direction: column;
  gap: 0.8rem;
}

.cta-sidebar .social-button {
  width: 100%;
